    piece_values = {
        chess.PAWN: 1,
        chess.KNIGHT: 3,
        chess.BISHOP: 3,
        chess.ROOK: 5,
        chess.QUEEN: 9,
        chess.KING: 0  # King value is not used in material count
    }

    def material_score(board):
        score = 0
        for piece_type in piece_values:
            score += len(board.pieces(piece_type, chess.WHITE)) * piece_values[piece_type]
            score -= len(board.pieces(piece_type, chess.BLACK)) * piece_values[piece_type]
        return score

    def control_score(board):
        score = 0
        for square in chess.SQUARES:
            if board.is_attacked_by(chess.WHITE, square):
                score += 1
            if board.is_attacked_by(chess.BLACK, square):
                score -= 1
        return score

    def mobility_score(board):
        white_moves = len(list(board.legal_moves))  # Count legal moves for white
        black_moves = len(list(board.legal_moves))  # Count legal moves for black
        return white_moves - black_moves

    def check_mate_chances(board):
        if board.is_checkmate():
            return -float('inf') if board.turn == chess.WHITE else float('inf')
        elif board.is_check():
            return 1 if board.turn == chess.WHITE else -1
        return 0

    board = chess.Board(fen)
    score = material_score(board) + control_score(board) + mobility_score(board) + check_mate_chances(board)

    return score

